package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.SupWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_OPZEG_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRESTATIEVERHOUDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

@Slf4j
public class BerekenBvOpzegVergoedingen extends AbstractBerekenBv {

    public BerekenBvOpzegVergoedingen(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY) && BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvOpzegVergoedingen(opdrachtContext, persoon, opdracht, rekenTijd);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBvOpzegVergoedingen(RekenContext opdrachtContext, Persoon persoon, Opdracht opdracht, RekenTijd rekenTijd) {
        LoonElementManager manager = opdrachtContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
        RekenBvKey bvKey;
        RekenBbKey bbKey;
        RekenBbKey bbTeoKey;
        if (rekenTijd.isAchterstal) {
            bvKey = BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY;
            bbKey = BELASTBAAR_ACHTERSTAL_KEY;
            bbTeoKey = BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY;
        } else {
            bvKey = BEDRIJFSVOORHEFFING_OPZEG_VERGOEDING_KEY;
            bbKey = BELASTBAAR_KEY;
            bbTeoKey = BELASTBAAR_THEORETISCH_JAARWEDDE_KEY;
        }
        Money belastbaar = getBelastbaar(bvKey, bbKey, opdrachtElementen);
        log.debug("belastbaar:{}", belastbaar);
        if (belastbaar.signum() != 0) {
            Money jaarInkomen = opdrachtContext.getMoney(bbTeoKey);
            Money bedrijfsvoorheffing = berekenBvOpzegVergoedingen(persoon, belastbaar, jaarInkomen, opdrachtContext);
            herverdeelBedrijfsvoorheffing(bvKey, bedrijfsvoorheffing, bbKey, belastbaar, opdrachtElementen);
        }
        log.trace("opdrachtElementen:{}", opdrachtElementen);
    }

    private Money berekenBvOpzegVergoedingen(Persoon persoon, Money belastbaar, Money jaarInkomen, RekenContext opdrachtContext) {
        RegulManager regulManager = opdrachtContext.getUnchecked(REGUL_MANAGER_KEY);
        Money bedrijfsvoorheffing = Money.ZERO;
        Opper opper = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
        SupWrkwBv fiscaleWerkwijze = opper.getOpdrachtFiscaliteit().getWerkwijzeSupplement();
        log.debug("{};fiscaleWerkwijze:{}", LogTools.toSimpleLog(opper.getOpdracht()), fiscaleWerkwijze);

        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        boolean isStagairVastbenoemd = RekenTools.isStagairVastbenoemd(rekenTijd, new SleutelGegevensSingleOpper(opper));

        switch (fiscaleWerkwijze) {
            case BAREMA_GN_KUMUL:
                bedrijfsvoorheffing = werkwijzeBaremaGeenCumul(persoon, belastbaar, jaarInkomen, isStagairVastbenoemd, rekenTijd, regulManager);
                break;
            case PERCENTAGE:
                bedrijfsvoorheffing = werkwijzePercentage(opper, belastbaar);
                break;
            case BEDRAG:
                bedrijfsvoorheffing = opper.getOpdrachtFiscaliteit().getBedragSupplement();
                break;
            case BAREMA_INV_PVH:
                BigDecimal prestatieVerhouding = opdrachtContext.getDoubleKey(PRESTATIEVERHOUDING_KEY, opper);
                if (prestatieVerhouding.signum() == 0) {
                    prestatieVerhouding = BigDecimal.ONE;
                    regulManager.doRegulException(opper.getOpdracht(), Regulkode.BASISBETAALBREUK_NUL);
                }
                bedrijfsvoorheffing =
                        werkwijzeBaremaInvPvh(persoon, belastbaar, jaarInkomen, prestatieVerhouding, isStagairVastbenoemd, rekenTijd, regulManager);
                break;
            default:
                regulManager.doRegulException(opper.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
                break;
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

    private Money werkwijzeBaremaGeenCumul(
            Persoon persoon, Money belastbaar, Money jaarInkomen, boolean isStagairVastbenoemd, RekenTijd rekenTijd,
            RegulManager regulManager) {
        Money bedrijfsvoorheffing;
        Money grens = fiscaleConstanten.getGrensOpzegVergoedingen();
        log.debug("grens opzegVergoedingen achterstal:{}", grens);
        if (belastbaar.compareTo(grens) <= 0) {
            bedrijfsvoorheffing = berekenBVGewoneBezoldigingBarema(persoon, belastbaar, false, isStagairVastbenoemd, rekenTijd, regulManager);
        } else {
            bedrijfsvoorheffing = berekenBVAchterstalBarema(persoon, jaarInkomen, belastbaar, rekenTijd);
        }
        return bedrijfsvoorheffing;
    }

    private Money werkwijzePercentage(Opper opper, Money belastbaar) {
        BigDecimal percentage = opper.getOpdrachtFiscaliteit().getPercentageSupplement().movePointLeft(2);
        log.debug("percentage:{}", percentage);
        return belastbaar.multiply(percentage).round(2);
    }

    private Money werkwijzeBaremaInvPvh(
            Persoon persoon, Money belastbaar, Money jaarInkomen, BigDecimal prestatieVerhouding,
            boolean isStagairVastbenoemd, RekenTijd rekenTijd, RegulManager regulManager) {
        Money bedrijfsvoorheffing;
        Money grens = fiscaleConstanten.getGrensOpzegVergoedingen();
        log.debug("grens opzegVergoedingen achterstal:{}", grens);
        if (belastbaar.compareTo(grens) <= 0) {
            Money belastbaarInvPvh = belastbaar.divide(prestatieVerhouding);
            bedrijfsvoorheffing = berekenBVGewoneBezoldigingBarema(persoon, belastbaarInvPvh, false, isStagairVastbenoemd, rekenTijd, regulManager);
            bedrijfsvoorheffing = bedrijfsvoorheffing.multiply(prestatieVerhouding);
        } else {
            Money jaarInkomenInvPvh = jaarInkomen.divide(prestatieVerhouding);
            bedrijfsvoorheffing = berekenBVAchterstalBarema(persoon, jaarInkomenInvPvh, belastbaar, rekenTijd);
        }
        return bedrijfsvoorheffing;
    }
}
